function toggleNavbar(){navbar.classList.toggle("opened");const e=navbar.classList.contains("opened");navbarToggle.setAttribute("aria-label",e?"Close navigation menu.":"Open navigation menu.")}function openMobileNavbar(){navbar.classList.add("opened"),navbarToggle.setAttribute("aria-label","Close navigation menu.")}function closeMobileNavbar(){navbar.classList.remove("opened"),navbarToggle.setAttribute("aria-label","Open navigation menu.")}function stopPropagation(e){e.stopPropagation()}let navbar=document.querySelector(".navbar"),navbarToggle=navbar.querySelector(".navbar-toggle"),navbarMenu=navbar.querySelector(".navbar-menu"),navbarLinksContainer=navbar.querySelector(".navbar-links");navbarToggle.addEventListener("click",toggleNavbar),navbarLinksContainer.addEventListener("click",stopPropagation),navbarMenu.addEventListener("click",closeMobileNavbar)